script:
frappe.ui.form.on('Item', {
  refresh(frm) {

    // 🔴 Highlight mandatory fields
    ['item_code', 'item_name', 'item_group'].forEach(field => {
      frm.fields_dict[field].$wrapper
        .css('background-color', '#fff5f5')
        .css('border-left', '4px solid #e74c3c')
        .css('border-radius', '4px')
        .css('padding', '6px');
    });

    // 🟡 Highlight important but optional fields
    ['standard_selling_rate', 'opening_stock'].forEach(field => {
      frm.fields_dict[field].$wrapper
        .css('background-color', '#fffde7')
        .css('border-left', '4px solid #f1c40f')
        .css('border-radius', '4px')
        .css('padding', '6px');
    });

    // 🔵 Highlight asset-related fields
    ['is_fixed_asset', 'asset_category'].forEach(field => {
      frm.fields_dict[field].$wrapper
        .css('background-color', '#f0f8ff')
        .css('border-left', '4px solid #3498db')
        .css('border-radius', '4px')
        .css('padding', '6px');
    });

  }
});

frappe.listview_settings["Item"] = {
    refresh: function(listview) {
        setTimeout(() => {
            const style_id = "item-list-compact-columns";

            if (!document.getElementById(style_id)) {
                const style = document.createElement("style");
                style.id = style_id;
                style.innerHTML = `
                    /* Make first/title column smaller */
                    .list-row-col.list-subject {
                        flex: 0 0 120px !important;
                        max-width: 120px !important;
                    }

                    /* Make ID column smaller */
                    .list-row-col.ellipsis.hidden-xs {
                        flex: 0 0 140px !important;
                        max-width: 140px !important;
                    }
                `;
                document.head.appendChild(style);
            }
        }, 300);
    }
};
